// frontend/src/components/workers/WorkerProfile.js
import React, { useState, useEffect } from 'react';
import { useParams, Link } from 'react-router-dom';
import api from '../../services/api';
import { useAuth } from '../../contexts/AuthContext';
import './WorkerProfile.css';

const WorkerProfile = () => {
    const { id } = useParams();
    const { user } = useAuth();
    const [worker, setWorker] = useState(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');
    const [isEditing, setIsEditing] = useState(false);
    const [formData, setFormData] = useState({});

    useEffect(() => {
        loadWorkerProfile();
    }, [id]);

    const loadWorkerProfile = async () => {
        setLoading(true);
        try {
            const response = await api.get(`/workers/${id}`);
            if (response.data.success) {
                setWorker(response.data.data);
                setFormData(response.data.data);
            } else {
                setError('Worker not found');
            }
        } catch (error) {
            console.error('Error loading worker:', error);
            setError('Failed to load worker profile');
        } finally {
            setLoading(false);
        }
    };

    const handleInputChange = (e) => {
        const { name, value } = e.target;
        setFormData({
            ...formData,
            [name]: value
        });
    };

    const handleArrayChange = (e, field) => {
        const values = e.target.value.split(',').map(s => s.trim());
        setFormData({
            ...formData,
            [field]: values
        });
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        try {
            const response = await api.put('/worker/profile', formData);
            if (response.data.success) {
                setIsEditing(false);
                loadWorkerProfile();
            } else {
                setError('Failed to update profile');
            }
        } catch (error) {
            console.error('Update error:', error);
            setError('Network error');
        } finally {
            setLoading(false);
        }
    };

    if (loading) {
        return <div className="loading-spinner">Loading profile...</div>;
    }

    if (error || !worker) {
        return (
            <div className="error-container">
                <h2>Error</h2>
                <p>{error || 'Worker not found'}</p>
                <Link to="/" className="btn-primary">Back Home</Link>
            </div>
        );
    }

    const isOwnProfile = user?.id === worker.id;

    return (
        <div className="worker-profile-container">
            <div className="worker-profile">
                {/* Header */}
                <div className="profile-header">
                    <div className="profile-avatar">
                        {worker.name?.charAt(0) || '👤'}
                    </div>
                    <div className="profile-title">
                        <h1>{worker.name}</h1>
                        <p className="worker-location">📍 {worker.township}</p>
                        <div className="worker-badges">
                            {worker.is_verified && (
                                <span className="badge verified">✓ Verified</span>
                            )}
                            <span className="badge level">Level {worker.verification_level}</span>
                        </div>
                    </div>
                    {isOwnProfile && !isEditing && (
                        <button 
                            className="btn-edit"
                            onClick={() => setIsEditing(true)}
                        >
                            ✎ Edit Profile
                        </button>
                    )}
                </div>

                {/* Stats */}
                <div className="profile-stats">
                    <div className="stat-card">
                        <span className="stat-value">{worker.rating?.toFixed(1) || '0.0'}</span>
                        <span className="stat-label">Rating</span>
                    </div>
                    <div className="stat-card">
                        <span className="stat-value">{worker.completed_jobs || 0}</span>
                        <span className="stat-label">Jobs Done</span>
                    </div>
                    <div className="stat-card">
                        <span className="stat-value">{worker.review_count || 0}</span>
                        <span className="stat-label">Reviews</span>
                    </div>
                </div>

                {isEditing ? (
                    // Edit Mode
                    <form onSubmit={handleSubmit} className="profile-edit-form">
                        <h2>Edit Profile</h2>

                        <div className="form-group">
                            <label>Primary Skill</label>
                            <input
                                type="text"
                                name="primary_skill"
                                value={formData.primary_skill || ''}
                                onChange={handleInputChange}
                                placeholder="e.g., Gardening"
                            />
                        </div>

                        <div className="form-group">
                            <label>Skills (comma separated)</label>
                            <input
                                type="text"
                                name="skills"
                                value={formData.skills ? formData.skills.join(', ') : ''}
                                onChange={(e) => handleArrayChange(e, 'skills')}
                                placeholder="Gardening, Painting, Plumbing"
                            />
                        </div>

                        <div className="form-row">
                            <div className="form-group">
                                <label>Experience (years)</label>
                                <input
                                    type="number"
                                    name="experience_years"
                                    value={formData.experience_years || 0}
                                    onChange={handleInputChange}
                                    min="0"
                                />
                            </div>

                            <div className="form-group">
                                <label>Travel Radius (km)</label>
                                <input
                                    type="number"
                                    name="travel_radius_km"
                                    value={formData.travel_radius_km || 5}
                                    onChange={handleInputChange}
                                    min="1"
                                    max="50"
                                />
                            </div>
                        </div>

                        <div className="form-row">
                            <div className="form-group">
                                <label>Hourly Rate Min (R)</label>
                                <input
                                    type="number"
                                    name="hourly_rate_min"
                                    value={formData.hourly_rate_min || 100}
                                    onChange={handleInputChange}
                                    min="0"
                                />
                            </div>

                            <div className="form-group">
                                <label>Hourly Rate Max (R)</label>
                                <input
                                    type="number"
                                    name="hourly_rate_max"
                                    value={formData.hourly_rate_max || 300}
                                    onChange={handleInputChange}
                                    min="0"
                                />
                            </div>
                        </div>

                        <div className="form-group">
                            <label>Available Days</label>
                            <input
                                type="text"
                                name="available_days"
                                value={formData.available_days || ''}
                                onChange={handleInputChange}
                                placeholder="Mon, Tue, Wed"
                            />
                        </div>

                        <div className="form-group">
                            <label>Available Hours</label>
                            <input
                                type="text"
                                name="available_hours"
                                value={formData.available_hours || ''}
                                onChange={handleInputChange}
                                placeholder="9am-5pm"
                            />
                        </div>

                        <div className="form-group">
                            <label>Bio</label>
                            <textarea
                                name="bio"
                                value={formData.bio || ''}
                                onChange={handleInputChange}
                                rows="4"
                                placeholder="Tell clients about yourself..."
                            />
                        </div>

                        <div className="form-actions">
                            <button 
                                type="button" 
                                className="btn-cancel"
                                onClick={() => setIsEditing(false)}
                            >
                                Cancel
                            </button>
                            <button 
                                type="submit" 
                                className="btn-save"
                                disabled={loading}
                            >
                                {loading ? 'Saving...' : 'Save Changes'}
                            </button>
                        </div>
                    </form>
                ) : (
                    // View Mode
                    <div className="profile-details">
                        {/* Skills */}
                        <div className="details-section">
                            <h3>🛠️ Skills & Expertise</h3>
                            <div className="skills-list">
                                {worker.primary_skill && (
                                    <span className="skill-tag primary">{worker.primary_skill}</span>
                                )}
                                {worker.skills?.map((skill, index) => (
                                    <span key={index} className="skill-tag">{skill}</span>
                                ))}
                            </div>
                        </div>

                        {/* Rates */}
                        <div className="details-section">
                            <h3>💰 Rates</h3>
                            <div className="rates-info">
                                <div className="rate-item">
                                    <span className="rate-label">Hourly Rate:</span>
                                    <span className="rate-value">
                                        R{worker.hourly_rate_min || 100} - R{worker.hourly_rate_max || 300}
                                    </span>
                                </div>
                                <div className="rate-item">
                                    <span className="rate-label">Travel Radius:</span>
                                    <span className="rate-value">{worker.travel_radius_km || 5} km</span>
                                </div>
                            </div>
                        </div>

                        {/* Availability */}
                        <div className="details-section">
                            <h3>📅 Availability</h3>
                            <div className="availability-info">
                                <div className="avail-item">
                                    <span className="avail-label">Days:</span>
                                    <span className="avail-value">{worker.available_days || 'Flexible'}</span>
                                </div>
                                <div className="avail-item">
                                    <span className="avail-label">Hours:</span>
                                    <span className="avail-value">{worker.available_hours || 'Flexible'}</span>
                                </div>
                            </div>
                        </div>

                        {/* Bio */}
                        {worker.bio && (
                            <div className="details-section">
                                <h3>📝 About</h3>
                                <p className="bio-text">{worker.bio}</p>
                            </div>
                        )}

                        {/* Reviews */}
                        <div className="details-section">
                            <h3>⭐ Reviews</h3>
                            {worker.reviews?.length > 0 ? (
                                <div className="reviews-list">
                                    {worker.reviews.map((review, index) => (
                                        <div key={index} className="review-item">
                                            <div className="review-header">
                                                <span className="reviewer">{review.reviewer_name}</span>
                                                <span className="review-rating">{'⭐'.repeat(review.rating)}</span>
                                            </div>
                                            <p className="review-comment">{review.comment}</p>
                                            <p className="review-job">{review.job_title}</p>
                                        </div>
                                    ))}
                                </div>
                            ) : (
                                <p className="no-reviews">No reviews yet</p>
                            )}
                        </div>

                        {/* Completed Jobs */}
                        <div className="details-section">
                            <h3>✅ Completed Jobs</h3>
                            {worker.completed_jobs?.length > 0 ? (
                                <div className="jobs-list">
                                    {worker.completed_jobs.map((job, index) => (
                                        <div key={index} className="job-item">
                                            <h4>{job.title}</h4>
                                            <p>{job.completion_notes}</p>
                                            <Link to={`/jobs/${job.id}`}>View Details →</Link>
                                        </div>
                                    ))}
                                </div>
                            ) : (
                                <p className="no-jobs">No completed jobs yet</p>
                            )}
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
};

export default WorkerProfile;
